body_template:
{
  "query": "SELECT COUNT(1) OVER() AS TotalRows, * FROM dbo.Accounts ORDER BY AccountKey ASC OFFSET @offset ROWS FETCH NEXT @pageSize ROWS ONLY",
  "params": {
    "offset": {offset},
    "pageSize": {limit}
  }
}

{
  "query": "SELECT COUNT(1) OVER() AS TotalRows, * FROM dbo.Items ORDER BY ID ASC OFFSET @offset ROWS FETCH NEXT @pageSize ROWS ONLY",
  "params": {
    "offset": {offset},
    "pageSize": {limit}
  }
}

{
  "query": "SELECT TOP (1) * FROM dbo.Accounts WHERE AccountKey = @AccountKey",
  "params": {
    "AccountKey": "{AccountKey}"
  }
}

{
  "query": "SELECT TOP (1) * FROM dbo.Items WHERE ItemKey = @ItemKey",
  "params": {
    "ItemKey": "{ItemKey}"
  }
}

{
  "query": "SELECT doc.*, JSON_QUERY((SELECT sm.*, priceAfterDiscount = ROUND(ISNULL(sm.TFtal, ISNULL(sm.Price,0)*ISNULL(sm.Quantity,0)) * CASE WHEN ISNULL(sm.DiscountPrc,0) > 1 THEN (1-ISNULL(sm.DiscountPrc,0)/100.0) ELSE (1-ISNULL(sm.DiscountPrc,0)) END * x.discFactor, 2) FROM dbo.StockMoves sm WHERE sm.StockId = doc.ID ORDER BY sm.ID ASC FOR JSON PATH)) AS lines, calc.totalBeforeDiscount, calc.totalAfterDiscount, calc.totalTax, doc.TFtal AS totalPriceAfterTax, (doc.TFtal - doc.TFtalVat) AS totalTaxSimple FROM dbo.Stock doc CROSS APPLY (SELECT baseBeforeDiscount = ISNULL(doc.TFtalVat,0) + ISNULL(doc.TFtalVatFree,0), discFactor = CASE WHEN ABS(((ISNULL(doc.TFtalVat,0)+ISNULL(doc.TFtalVatFree,0))*(1-ISNULL(doc.DiscountPrc,0)/100.0) + (ISNULL(doc.TFtalVat,0)*(1-ISNULL(doc.DiscountPrc,0)/100.0))*(ISNULL(doc.VatPrc,0)/100.0)) - ISNULL(doc.TFtal,0)) <= ABS(((ISNULL(doc.TFtalVat,0)+ISNULL(doc.TFtalVatFree,0))*(1-ISNULL(doc.DiscountPrc,0)) + (ISNULL(doc.TFtalVat,0)*(1-ISNULL(doc.DiscountPrc,0)))*(ISNULL(doc.VatPrc,0)/100.0)) - ISNULL(doc.TFtal,0)) THEN (1-ISNULL(doc.DiscountPrc,0)/100.0) ELSE (1-ISNULL(doc.DiscountPrc,0)) END) x CROSS APPLY (SELECT totalBeforeDiscount = x.baseBeforeDiscount, totalAfterDiscount = ROUND(x.baseBeforeDiscount * x.discFactor, 2), totalTax = ROUND(ISNULL(doc.TFtal,0) - (x.baseBeforeDiscount * x.discFactor), 2)) calc WHERE doc.ID = @uniqueId",
  "params": {
    "uniqueId": "{documentNumber}"
  }
}

{
  "query": "WITH ids AS (
  SELECT TRY_CONVERT(int, LTRIM(RTRIM(value))) AS NoteID
  FROM STRING_SPLIT(@noteIdsCsv, ',')
  WHERE LTRIM(RTRIM(value)) <> ''
)
SELECT TOP (1000)
  [ID], [KeF], [Note], [ItemFlag], [NoteID], [Dumi]
FROM dbo.ExtraNotes
WHERE [NoteID] IN (SELECT NoteID FROM ids WHERE NoteID IS NOT NULL)",
  "params": {
    "noteIdsCsv": "{noteIdsCsv}"
  }
}

{
  "query": "SELECT [Note]\nFROM dbo.ExtraNotes\nWHERE NoteID = @NoteId AND KeF = @Kef",
  "params": {
    "NoteId": "{NoteId}",
    "Kef": "{Kef}"
  }
}

{
  "query": "SELECT DISTINCT WAREHOUSE FROM dbo.vBalItemWarehouse ORDER BY WAREHOUSE",
  "params": {
    "offset": 0,
    "pageSize": 1000
  }
}

{
  "query": "SELECT COUNT(1) OVER() AS TotalRows, *\nFROM dbo.Items\nWHERE ItemName LIKE '%' + @itemName + '%'\nORDER BY ID ASC\nOFFSET @offset ROWS FETCH NEXT @pageSize ROWS ONLY",
  "params": {
    "itemName": "{name}",
    "offset": 0,
    "pageSize": 100
  }
}

{
  "query": "SELECT * FROM dbo.ExtraNoteNames"
}

{
  "query": "SELECT j.StockID, balMatch.OPENSUF, balMatch.JTMDEBITCREDIT, j.ValueDate, j.DueDate, j.Referance FROM dbo.VOPENJURNALMATCH AS balMatch JOIN dbo.JurnalTrans AS j ON balMatch.JTID = j.TransID WHERE balMatch.AACCOUNTKEY = @userExtId ORDER BY j.ValueDate, j.TransID",
  "params": {
    "userExtId": "{userExtId}"
  }
}

{
  "query": "SELECT s1.DocumentID, s1.DocNumber, ch.CheqNumber, ch.SuF, ch.ValueDate, s1.ValueDate AS DocValueDate FROM dbo.Stock AS s1 JOIN dbo.Cheqs AS ch ON s1.Id = ch.StockID WHERE s1.AccountKey = @userExtId AND s1.DocumentID IN ('1','9','37','31') AND ch.ValueDate > DATEADD(day, DATEDIFF(day, 0, GETDATE()), 0) ORDER BY ch.ValueDate, s1.DocNumber",
  "params": {
    "userExtId": "{userExtId}"
  }
}

{
  "query": "SELECT * FROM dbo.ItemSortNames",
  "params": {
  }
}
